// Example: Token bucket rate limiter for Express.js
const rateLimit = require('express-rate-limit');

const tokenBucketLimiter = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 100, // limit each IP to 100 requests per windowMs
  message: 'Too many requests from this IP, please try again later.',
  standardHeaders: true,
  legacyHeaders: false,
  // Customize for your MCP server's edge cases
  skip: (req) => req.user?.isAdmin, // exempt admins
  keyGenerator: (req) => req.ip + (req.user?.id || ''), // group by user/IP
});

// Apply to all requests
app.use(tokenBucketLimiter);

This snippet shows how an AI might generate a practical rate-limiting solution tailored to specific needs, handling edge cases like admin exemptions and user-based grouping.
